import{_ as e,o as a,c as i,a3 as s}from"./chunks/framework.LBeL10WQ.js";const g=JSON.parse('{"title":"Banner Specifications","description":"","frontmatter":{"title":"Banner Specifications"},"headers":[],"relativePath":"en/advertisers/display-email/specs.md","filePath":"en/advertisers/display-email/specs.md"}'),r={name:"en/advertisers/display-email/specs.md"};function n(o,t,l,d,c,m){return a(),i("div",null,[...t[0]||(t[0]=[s('<h1 id="banner-specifications" tabindex="-1">Banner Specifications <a class="header-anchor" href="#banner-specifications" aria-label="Permalink to &quot;Banner Specifications&quot;">​</a></h1><p>Standards to be met to ensure optimal display on all email clients (Outlook, Gmail, Apple Mail...).</p><hr><h2 id="standard-formats" tabindex="-1">Standard Formats <a class="header-anchor" href="#standard-formats" aria-label="Permalink to &quot;Standard Formats&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Format</th><th style="text-align:left;">Dimensions (W × H)</th><th style="text-align:left;">Typical placement</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Large Banner</strong> (Leaderboard)</td><td style="text-align:left;"><strong>600 × 150 px</strong> <em>(sometimes 640 px)</em></td><td style="text-align:left;">Header or core of email — most impactful format</td></tr><tr><td style="text-align:left;"><strong>Block</strong> (Rectangle)</td><td style="text-align:left;"><strong>300 × 250 px</strong></td><td style="text-align:left;">Side column or footer of email — compact format</td></tr></tbody></table><hr><h2 id="technical-constraints" tabindex="-1">Technical Constraints <a class="header-anchor" href="#technical-constraints" aria-label="Permalink to &quot;Technical Constraints&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Criterion</th><th style="text-align:left;">Specification</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>File Type</strong></td><td style="text-align:left;">JPG, PNG, or GIF</td></tr><tr><td style="text-align:left;"><strong>Color Mode</strong></td><td style="text-align:left;">RGB</td></tr><tr><td style="text-align:left;"><strong>Maximum Weight</strong></td><td style="text-align:left;">150 KB — recommended &lt; <strong>80 KB</strong> for fast loading on mobile</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Animated GIFs — first frame rule</p><p>Animated GIFs are accepted, but <strong>Outlook (desktop versions) only displays the first image</strong>.</p><p>→ The main information and the Call-to-Action must imperatively figure on the <strong>first frame</strong>.</p></div><hr><h2 id="design-best-practices" tabindex="-1">Design Best Practices <a class="header-anchor" href="#design-best-practices" aria-label="Permalink to &quot;Design Best Practices&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">White background: add a border</p><p>If your banner has a white background, it may blend into the email background and become invisible.</p><p>Add a <strong>1 px gray border</strong> (<code>#cccccc</code>) all around your visual to clearly delimit it.</p></div><div class="tip custom-block"><p class="custom-block-title">Mobile readability</p><p>On mobile, a 600 px banner is reduced to ~350 px wide. Avoid fonts that are too thin or too small — <strong>recommended minimum size: 16 px</strong>.</p></div>',13)])])}const f=e(r,[["render",n]]);export{g as __pageData,f as default};
